mapper.select:
SELECT COUNT(*) FROM party_student_progress p INNER JOIN t_user u ON u.id = p.user_id WHERE 1 = 1
AND p.current_stage_code = #{q.stageCode}
AND (u.real_name LIKE '%' || #{q.keyword} || '%' OR u.student_no LIKE '%' || #{q.keyword} || '%')

SELECT COUNT(*) FROM party_report r INNER JOIN t_user u ON u.id = r.user_id WHERE 1 = 1
AND r.status = #{q.status}
AND (u.real_name LIKE '%' || #{q.keyword} || '%' OR r.title LIKE '%' || #{q.keyword} || '%')

SELECT COUNT(*) FROM party_activity_application a INNER JOIN t_user u ON u.id = a.user_id WHERE 1 = 1
AND a.status = #{q.status}
AND (u.real_name LIKE '%' || #{q.keyword} || '%' OR a.title LIKE '%' || #{q.keyword} || '%')
